import{_ as p,c as e}from"./app.f21a7cce.js";const r={},t=e('<h1 id="\u6D45\u8C08\u5168\u94FE\u8DEF\u538B\u6D4B" tabindex="-1"><a class="header-anchor" href="#\u6D45\u8C08\u5168\u94FE\u8DEF\u538B\u6D4B" aria-hidden="true">#</a> \u6D45\u8C08\u5168\u94FE\u8DEF\u538B\u6D4B</h1><p>\u4F60\u597D\uFF0C\u6211\u662F\u8339\u70B3\u665F\u3002\u4ECA\u5929\u6211\u548C\u4F60\u5206\u4EAB\u7684\u4E3B\u9898\u662F\uFF1A\u6D45\u8C08\u5168\u94FE\u8DEF\u538B\u6D4B\u3002</p><p>\u65F6\u5149\u98DE\u901D\uFF0C\u4ECE\u4E13\u680F\u4E0A\u7EBF\u81F3\u4ECA\uFF0C\u6211\u5DF2\u7ECF\u548C\u4F60\u5206\u4EAB\u4E86 52 \u7BC7\u6587\u7AE0\u548C 7 \u7BC7\u7B54\u7591\u6587\u7AE0\uFF0C\u548C\u4F60\u5206\u4EAB\u4E86\u8F6F\u4EF6\u6D4B\u8BD5\u4E2D\u7684\u5404\u4E2A\u4E3B\u9898\uFF0C\u5E0C\u671B\u5DF2\u7ECF\u5E2E\u4F60\u6784\u5EFA\u4E86\u4E00\u5E45\u8F6F\u4EF6\u6D4B\u8BD5\u7684\u77E5\u8BC6\u5168\u666F\u56FE\u3002</p><p>\u5728\u524D\u9762\u7684\u201C\u6027\u80FD\u6D4B\u8BD5\u201D\u7CFB\u5217\u6587\u7AE0\u4E2D\uFF0C\u6211\u4EE5 LoadRunner \u4E3A\u4F8B\uFF0C\u548C\u4F60\u5206\u4EAB\u4E86\u4F20\u7EDF\u4F01\u4E1A\u5728\u5B9E\u9645\u5F00\u5C55\u4F01\u4E1A\u7EA7\u6027\u80FD\u6D4B\u8BD5\u7684\u5B9E\u8DF5\u3002\u5E76\u4E14\u5728\u7B2C 32 \u7BC7\u6587\u7AE0\u300A\u65E0\u5B9E\u4F8B\u65E0\u771F\u76F8\uFF1A\u57FA\u4E8E LoadRunner \u5B9E\u73B0\u4F01\u4E1A\u7EA7\u670D\u52A1\u5668\u7AEF\u6027\u80FD\u6D4B\u8BD5\u7684\u5B9E\u8DF5\uFF08\u4E0A\uFF09\u300B\u4E2D\uFF0C\u6211\u548C\u4F60\u5206\u4EAB\u4E86\u8FD9\u4E48\u5B89\u6392\u7684\u539F\u56E0\uFF0C\u5E76\u627F\u8BFA\u5728\u4E13\u680F\u7ED3\u675F\u524D\uFF0C\u901A\u8FC7\u4E00\u7BC7\u201C\u52A0\u9910\u201D\u6587\u7AE0\uFF0C\u548C\u4F60\u5206\u4EAB\u5F00\u5C55\u5168\u94FE\u8DEF\u538B\u6D4B\u7684\u96BE\u70B9\uFF0C\u4EE5\u53CA\u5E94\u5BF9\u65B9\u6848\u3002</p><p>\u73B0\u5728\uFF0C\u5C31\u662F\u6211\u8DF5\u884C\u627F\u8BFA\u7684\u65F6\u95F4\u4E86\u3002</p><p>\u6211\u4E5F\u4E0D\u592A\u6E05\u695A\uFF0C\u4F60\u73B0\u5728\u5177\u5907\u591A\u5C11\u5168\u94FE\u8DEF\u538B\u6D4B\u7684\u77E5\u8BC6\u3002\u6240\u4EE5\uFF0C\u6211\u4F1A\u5148\u548C\u4F60\u5206\u4EAB\u4E00\u4E9B\u5168\u94FE\u8DEF\u538B\u6D4B\u7684\u7406\u8BBA\u77E5\u8BC6\uFF0C\u7136\u540E\u518D\u5206\u4EAB\u5177\u4F53\u7684\u96BE\u70B9\u4EE5\u53CA\u89E3\u51B3\u601D\u8DEF\uFF0C\u5E2E\u4F60\u52A0\u6DF1\u7406\u89E3\uFF0C\u5E0C\u671B\u53EF\u4EE5\u8BA9\u4F60\u542C\u5F97\u660E\u767D\u3001\u5B66\u5F97\u4F1A\u3001\u7528\u5F97\u7740\u3002</p><p><strong>\u4EC0\u4E48\u662F\u5168\u94FE\u8DEF\u538B\u6D4B\uFF1F</strong></p><p>\u5168\u94FE\u8DEF\u538B\u6D4B\uFF0C\u662F\u57FA\u4E8E\u771F\u5B9E\u7684\u751F\u4EA7\u73AF\u5883\u6765\u6A21\u62DF\u6D77\u91CF\u7684\u5E76\u53D1\u7528\u6237\u8BF7\u6C42\u548C\u6570\u636E\uFF0C\u5BF9\u6574\u4E2A\u4E1A\u52A1\u94FE\u8DEF\u8FDB\u884C\u538B\u529B\u6D4B\u8BD5\uFF0C\u8BD5\u56FE\u627E\u5230\u6240\u6709\u6F5C\u5728\u6027\u80FD\u74F6\u9888\u70B9\u5E76\u6301\u7EED\u4F18\u5316\u7684\u5B9E\u8DF5\u3002</p><p>\u76EE\u524D\uFF0C\u4E00\u7EBF\u4E92\u8054\u7F51\u516C\u53F8\u7684\u5927\u578B\u7535\u5546\u5E73\u53F0\u90FD\u4F1A\u4E0D\u5B9A\u671F\u5730\u5F00\u5C55\u5168\u94FE\u8DEF\u538B\u6D4B\uFF0C\u6BD4\u5982\u6DD8\u5B9D\u3001\u4EAC\u4E1C\u3001\u997F\u4E86\u4E48\u548C\u7F8E\u56E2\u8FD9\u4E9B\u4F01\u4E1A\uFF0C\u57FA\u672C\u90FD\u5DF2\u7ECF\u6709\u4E86\u81EA\u5DF1\u7684\u5168\u94FE\u8DEF\u538B\u6D4B\u65B9\u6848\u548C\u5E73\u53F0\u3002</p><p>\u5176\u4E2D\uFF0C\u6700\u4E3A\u5178\u578B\u7684\u8981\u6570\u6DD8\u5B9D\u7684\u53CC 11 \u6D3B\u52A8\u4E86\u3002\u6BCF\u5E74\u5230\u4E86 11 \u6708 11 \u65E5\u7684\u96F6\u70B9\uFF0C\u6DD8\u5B9D\u7684\u6574\u4E2A\u7CFB\u7EDF\u90FD\u4F1A\u9762\u4E34\u6781\u5927\u7684\u6D41\u91CF\u51B2\u51FB\uFF0C\u5982\u679C\u4E8B\u5148\u6CA1\u6709\u7ECF\u8FC7\u5145\u5206\u7684\u6D4B\u8BD5\u548C\u5BB9\u91CF\u9884\u4F30\uFF0C\u5F88\u53EF\u80FD\u4F1A\u5728\u6D41\u91CF\u7206\u53D1\u65F6\u762B\u75EA\u3002</p><p>\u8BB0\u5F97\u5728\u65E9\u4E9B\u5E74\u7684\u6DD8\u5B9D\u53CC 11 \u5927\u4FC3\u4E2D\uFF0C\u5C31\u51FA\u73B0\u4E86\u4E0D\u540C\u7A0B\u5EA6\u7684\u7F51\u7AD9\u6545\u969C\uFF0C\u4E25\u91CD\u5F71\u54CD\u4E86\u7528\u6237\u4F53\u9A8C\uFF0C\u6240\u4EE5\u4ECE 2013 \u5E74\u5F00\u59CB\uFF0C\u6DD8\u5B9D\u5F00\u59CB\u5B9E\u65BD\u5168\u9762\u7684\u5168\u94FE\u8DEF\u538B\u6D4B\u3002\u7531\u4E8E\u5728\u771F\u6B63\u7684\u53CC 11 \u5230\u6765\u524D\uFF0C\u6DD8\u5B9D\u5185\u90E8\u5DF2\u7ECF\u6A21\u62DF\u4E86\u6BD4\u53CC 11 \u6D41\u91CF\u8FD8\u8981\u9AD8\u7684\u8D1F\u8F7D\uFF0C\u5E76\u4E14\u9010\u4E2A\u89E3\u51B3\u4E86\u5DF2\u7ECF\u53D1\u73B0\u7684\u95EE\u9898\uFF0C\u56E0\u6B64\u771F\u6B63\u53CC 11 \u5230\u6765\u7684\u65F6\u5019\uFF0C\u5C31\u4E0D\u4F1A\u51FA\u73B0\u4E25\u91CD\u7684\u95EE\u9898\u4E86\u3002</p><p>\u56E0\u6B64\uFF0C\u4E3A\u4E86\u9632\u6B62\u6B64\u7C7B\u4E8B\u6545\uFF0C\u6DD8\u5B9D\u4F1A\u5728\u6BCF\u5728\u53CC 11 \u4E4B\u524D\uFF0C\u5C31\u5BF9\u7CFB\u7EDF\u7684\u7A33\u5B9A\u6027\u4EE5\u53CA\u8D1F\u8F7D\u627F\u53D7\u80FD\u529B\u8FDB\u884C\u5FC5\u8981\u7684\u6D4B\u8BD5\u548C\u8BC4\u4F30\u3002</p><p>\u5F53\u7136\uFF0C<strong>\u5168\u94FE\u8DEF\u538B\u6D4B\u7684\u5E94\u7528\u573A\u666F\uFF0C\u4E0D\u4EC5\u4EC5\u5305\u62EC\u9A8C\u8BC1\u7CFB\u7EDF\u5728\u5CF0\u503C\u671F\u95F4\u7684\u7A33\u5B9A\u6027\uFF0C\u8FD8\u4F1A\u5305\u542B\u65B0\u7CFB\u7EDF\u4E0A\u7EBF\u540E\u7684\u6027\u80FD\u74F6\u9888\u5B9A\u4F4D\u4EE5\u53CA\u7AD9\u70B9\u5BB9\u91CF\u7684\u7CBE\u51C6\u89C4\u5212\u3002</strong></p><p>\u6BD4\u5982\uFF0C\u7531\u4E8E\u67D0\u4E9B\u4E1A\u52A1\u6A21\u5757\u7684\u64CD\u4F5C\u8D1F\u8F7D\u4F1A\u96C6\u4E2D\u5230\u51E0\u4E2A\u6700\u6838\u5FC3\u7684\u7EC4\u4EF6\u4E0A\uFF0C\u90A3\u4E48\u901A\u8FC7\u5168\u94FE\u8DEF\u538B\u6D4B\u7684\u6A21\u62DF\uFF0C\u6211\u4EEC\u5C31\u80FD\u5FEB\u901F\u8BC6\u522B\u51FA\u54EA\u4E9B\u6A21\u5757\u7684\u8D1F\u8F7D\u8FC7\u5927\uFF0C\u54EA\u4E9B\u6A21\u5757\u7684\u8D1F\u8F7D\u504F\u5C0F\u3002\u8FD9\u6837\u6211\u4EEC\u5728\u5BF9\u7CFB\u7EDF\u8FDB\u884C\u6269\u5BB9\u65F6\uFF0C\u5C31\u53EF\u4EE5\u628A\u8D44\u6E90\u66F4\u591A\u5730\u7ED9\u5230\u90A3\u4E9B\u627F\u53D7\u5927\u8D1F\u8F7D\u7684\u6A21\u5757\uFF0C\u800C\u90A3\u4E9B\u627F\u53D7\u8D1F\u8F7D\u504F\u5C0F\u7684\u6A21\u5757\u5C31\u53EF\u4EE5\u8FDB\u884C\u9002\u5F53\u7684\u6536\u7F29\u6765\u8BA9\u51FA\u66F4\u591A\u7684\u53EF\u7528\u8D44\u6E90\u3002\u8FD9\uFF0C\u5C31\u662F\u7CBE\u51C6\u7684\u5BB9\u91CF\u89C4\u5212\u3002</p><p><strong>\u5355\u7CFB\u7EDF\u7684\u72EC\u7ACB\u538B\u6D4B</strong></p><p>\u65E9\u5148\u7684\u65F6\u5019\uFF0C\u538B\u6D4B\u5E76\u4E0D\u662F\u9488\u5BF9\u4E1A\u52A1\u7684\u5168\u94FE\u8DEF\u6765\u5F00\u5C55\u7684\uFF0C\u800C\u662F\u91C7\u7528\u4E86\u201C\u5404\u4E2A\u51FB\u7834\u201D\u7684\u539F\u5219\uFF0C\u5373\u5BF9\u751F\u4EA7\u73AF\u5883\u4E2D\u7684\u5355\u673A\u6216\u8005\u5355\u7CFB\u7EDF\u8FDB\u884C\u72EC\u7ACB\u7684\u538B\u6D4B\u3002\u8FD9\u65F6\uFF0C\u538B\u6D4B\u4E3B\u8981\u662F\u901A\u8FC7\u6A21\u62DF\u5355\u4E00\u7CFB\u7EDF\u7684\u6D77\u91CF\u5E76\u53D1\u8BF7\u6C42\u6765\u5B9E\u73B0\u7684\u3002\u800C\u6A21\u62DF\u6D77\u91CF\u8BF7\u6C42\u4E3B\u8981\u6709\u4E24\u79CD\u5B9E\u73B0\u65B9\u5F0F\uFF1A</p><ul><li>\u4E00\u79CD\u662F\uFF0C\u6839\u636E\u8BBE\u8BA1\u7684\u538B\u529B\u6765\u76F4\u63A5\u6A21\u62DF\u5927\u91CF\u7684\u5E76\u53D1\u8C03\u7528\uFF1B</li><li>\u53E6\u4E00\u79CD\u662F\uFF0C\u5148\u83B7\u53D6\u7EBF\u4E0A\u771F\u5B9E\u7684\u6D41\u91CF\u8BF7\u6C42\uFF0C\u7136\u540E\u7ECF\u8FC7\u6570\u636E\u6E05\u6D17\u540E\uFF0C\u518D\u56DE\u653E\u6A21\u62DF\u5927\u91CF\u7684\u5E76\u53D1\u8C03\u7528\u3002</li></ul><p>\u4E0D\u7BA1\u91C7\u7528\u7684\u662F\u54EA\u79CD\u65B9\u5F0F\uFF0C\u90FD\u4F1A\u6D89\u53CA\u6D41\u91CF\u6A21\u62DF\u3001\u6570\u636E\u51C6\u5907\u3001\u6570\u636E\u9694\u79BB\u7B49\u64CD\u4F5C\u3002\u9664\u6B64\u4E4B\u5916\uFF0C\u5355\u7CFB\u7EDF\u7684\u72EC\u7ACB\u538B\u6D4B\u5C40\u9650\u6027\u4E5F\u975E\u5E38\u660E\u663E\u3002</p><p>\u8FD9\u91CC\uFF0C\u6211\u628A\u5355\u7CFB\u7EDF\u72EC\u7ACB\u538B\u6D4B\u7684\u5C40\u9650\u6027\uFF0C\u5F52\u7EB3\u4E3A\u4E86\u4EE5\u4E0B\u51E0\u70B9\uFF1A</p><ul><li>\u5355\u7CFB\u7EDF\u538B\u6D4B\u7684\u65F6\u5019\uFF0C\u4F1A\u5047\u8BBE\u5176\u4F9D\u8D56\u7684\u6240\u6709\u7CFB\u7EDF\u80FD\u529B\u90FD\u662F\u65E0\u9650\u7684\uFF0C\u800C\u5B9E\u9645\u60C5\u51B5\u4E00\u5B9A\u4E0D\u662F\u8FD9\u6837\uFF0C\u8FD9\u5C31\u9020\u6210\u4E86\u5355\u7CFB\u7EDF\u538B\u6D4B\u7684\u6570\u636E\u666E\u904D\u6BD4\u8F83\u4E50\u89C2\u7684\u60C5\u51B5\uFF1B</li><li>\u5728\u5927\u538B\u529B\u73AF\u5883\u4E0B\uFF0C\u5404\u7CFB\u7EDF\u95F4\u7684\u76F8\u4E92\u8C03\u7528\u4F1A\u6210\u4E3A\u7CFB\u7EDF\u74F6\u9888\uFF0C\u4F46\u8FD9\u5728\u5355\u7CFB\u7EDF\u538B\u6D4B\u7684\u65F6\u5019\u6839\u672C\u65E0\u6CD5\u4F53\u73B0\uFF1B</li><li>\u5927\u538B\u529B\u73AF\u5883\u4E0B\uFF0C\u5404\u7CFB\u7EDF\u8FD8\u4F1A\u51FA\u73B0\u62A2\u5360\u7CFB\u7EDF\u8D44\u6E90\uFF08\u6BD4\u5982\u7F51\u7EDC\u5E26\u5BBD\u3001\u6587\u4EF6\u53E5\u67C4\uFF09\u7684\u60C5\u51B5\uFF0C\u8FD9\u79CD\u8D44\u6E90\u62A2\u5360\u5FC5\u7136\u4F1A\u5F15\u5165\u6027\u80FD\u95EE\u9898\uFF0C\u4F46\u662F\u8FD9\u7C7B\u95EE\u9898\u5728\u5355\u7CFB\u7EDF\u538B\u6D4B\u8FC7\u7A0B\u4E2D\u4E5F\u65E0\u6CD5\u4F53\u73B0\u51FA\u6765\uFF1B</li><li>\u7531\u4E8E\u662F\u5355\u7CFB\u7EDF\u6D4B\u8BD5\uFF0C\u6240\u4EE5\u901A\u5E38\u90FD\u53EA\u4F1A\u5148\u9009\u62E9\u6700\u6838\u5FC3\u7684\u7CFB\u7EDF\u6765\u6D4B\u8BD5\uFF0C\u8FD9\u5C31\u610F\u5473\u7740\u5176\u4ED6\u7684\u975E\u6838\u5FC3\u7CFB\u7EDF\u4F1A\u88AB\u5FFD\u7565\uFF0C\u800C\u5728\u5B9E\u9645\u9879\u76EE\u4E2D\uFF0C\u8FD9\u4E9B\u975E\u6838\u5FC3\u7CFB\u7EDF\u4E5F\u5F88\u6709\u53EF\u80FD\u4F1A\u9020\u6210\u6027\u80FD\u74F6\u9888\u3002</li></ul><p>\u56E0\u6B64\uFF0C\u4E3A\u4E86\u89E3\u51B3\u5355\u7CFB\u7EDF\u72EC\u7ACB\u538B\u6D4B\u7684\u4E00\u7CFB\u5217\u95EE\u9898\uFF0C\u4E1A\u754C\u5C31\u884D\u751F\u51FA\u4E86\u5168\u94FE\u8DEF\u538B\u6D4B\u3002\u5168\u94FE\u8DEF\u538B\u6D4B\u4F1A\u628A\u6574\u4E2A\u7CFB\u7EDF\u770B\u4F5C\u4E00\u4E2A\u6574\u4F53\uFF0C\u7136\u540E\u5728\u771F\u5B9E\u7684\u751F\u4EA7\u73AF\u5883\u4E0A\u5C3D\u53EF\u80FD\u771F\u5B9E\u5730\u53BB\u6A21\u62DF\u4E1A\u52A1\u7684\u6D77\u91CF\u5E76\u53D1\u64CD\u4F5C\uFF0C\u4EE5\u6B64\u6765\u8861\u91CF\u7CFB\u7EDF\u7684\u5B9E\u9645\u627F\u8F7D\u80FD\u529B\uFF0C\u6216\u8005\u627E\u51FA\u7CFB\u7EDF\u53EF\u80FD\u7684\u74F6\u9888\u70B9\u5E76\u7ED9\u51FA\u76F8\u5E94\u7684\u89E3\u51B3\u65B9\u6848\u3002</p><p>\u76EE\u524D\u6765\u770B\uFF0C\u5168\u94FE\u8DEF\u538B\u6D4B\u9700\u8981\u89E3\u51B3\u7684\u6280\u672F\u96BE\u70B9\u6709\u5F88\u591A\uFF0C\u8FD9\u91CC\u6211\u4F1A\u548C\u4F60\u8BA8\u8BBA\u5176\u4E2D\u6700\u91CD\u8981\u7684\u56DB\u4E2A\u70B9\uFF1A</p><ol><li>\u6D77\u91CF\u5E76\u53D1\u8BF7\u6C42\u7684\u53D1\u8D77\uFF1B</li><li>\u5168\u94FE\u8DEF\u538B\u6D4B\u6D41\u91CF\u7684\u9694\u79BB\uFF1B</li><li>\u5B9E\u9645\u4E1A\u52A1\u8D1F\u8F7D\u7684\u6A21\u62DF\uFF1B</li><li>\u6D4B\u8BD5\u5B8C\u6210\u540E\u7684\u6570\u636E\u6E05\u7406\u3002</li></ol><p><strong>\u6D77\u91CF\u5E76\u53D1\u8BF7\u6C42\u7684\u53D1\u8D77</strong></p><p>\u7531\u4E8E\u5168\u94FE\u8DEF\u538B\u6D4B\u9700\u8981\u53D1\u8D77\u7684\u6D77\u91CF\u5E76\u53D1\uFF0C\u901A\u5E38\u4F1A\u8D85\u8FC7\u6BCF\u79D2 1000 \u4E07\u6B21\u4EE5\u4E0A\u8BF7\u6C42\u7684\u538B\u529B\u91CF\u7EA7\uFF0C\u6240\u4EE5\u4F20\u7EDF\u7684\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177 LoadRunner \u5DF2\u7ECF\u5F88\u96BE\u6EE1\u8DB3\u8981\u6C42\u4E86\uFF0C\u539F\u56E0\u6709\u4E8C\uFF1A</p><ul><li>\u4E00\u6765\uFF0CLoadRunner \u6309\u5E76\u53D1\u7528\u6237\u6570\u6536\u8D39\uFF0C\u8FD9\u5C31\u4F7F\u5F97\u91C7\u7528 LoadRunner \u8FDB\u884C\u4E92\u8054\u7F51\u7684\u5168\u94FE\u8DEF\u538B\u6D4B\u7684\u8D39\u7528\u4F1A\u5F02\u5E38\u9AD8\uFF1B</li><li>\u4E8C\u6765\uFF0CLoadRunner \u672C\u8EAB\u4E5F\u5F88\u96BE\u652F\u6301\u5343\u4E07\u7EA7\u4E43\u81F3\u4EBF\u7EA7\u7684\u6D77\u91CF\u5E76\u53D1\u3002</li></ul><p>\u6240\u4EE5\uFF0C\u4E1A\u754C\u57FA\u672C\u90FD\u662F\u91C7\u7528\u514D\u8D39\u7684 JMeter \u6765\u5B8C\u6210\u5168\u94FE\u8DEF\u538B\u6D4B\uFF0C\u8FD9\u4E5F\u662F JMeter \u8FD1\u51E0\u5E74\u88AB\u4E92\u8054\u7F51\u4F01\u4E1A\u5E7F\u6CDB\u4F7F\u7528\u7684\u539F\u56E0\u3002</p><p>\u4F46\u662F\uFF0C\u5373\u4FBF\u6709\u4E86 JMeter\uFF0C\u6211\u4EEC\u5728\u5F00\u5C55\u5168\u94FE\u8DEF\u538B\u6D4B\u65F6\uFF0C\u4E5F\u4F1A\u6709\u5F88\u591A\u95EE\u9898\u9700\u8981\u89E3\u51B3\u3002\u5176\u4E2D\uFF0C\u6700\u4E3B\u8981\u7684\u95EE\u9898\u5305\u62EC\u4EE5\u4E0B\u4E09\u4E2A\uFF1A</p><ol><li><p>\u867D\u7136\u91C7\u7528\u4E86\u5206\u5E03\u5F0F\u7684 JMeter \u65B9\u6848\uFF0C\u5E76\u53D1\u6570\u91CF\u4E5F\u4F1A\u5B58\u5728\u4E0A\u9650\uFF0C\u6BD4\u5982\u9762\u5BF9\u4EBF\u7EA7\u7684\u6D77\u91CF\u5E76\u53D1\u65F6\uFF0C\u4E3B\u8981\u539F\u56E0\u662F\u5206\u5E03\u5F0F\u7684 JMeter \u65B9\u6848\u4E2D\uFF0CMaster \u8282\u70B9\u4F1A\u6210\u4E3A\u6574\u4E2A\u538B\u6D4B\u53D1\u8D77\u7684\u74F6\u9888\u3002 \u4E3A\u4E86\u89E3\u51B3\u8FD9\u4E2A\u96BE\u9898\uFF0C\u5F88\u591A\u516C\u53F8\u5E76\u4E0D\u4F1A\u76F4\u63A5\u91C7\u7528\u5206\u5E03\u5F0F JMeter \u67B6\u6784\u6765\u5B8C\u6210\u6D77\u91CF\u5E76\u53D1\uFF0C\u800C\u662F\u4F1A\u4F7F\u7528 Jenkins Job \u5355\u72EC\u8C03\u7528 JMeter \u8282\u70B9\u6765\u63A7\u5236\u548C\u53D1\u8D77\u6D4B\u8BD5\u538B\u529B\u3002\u8FD9\u6837\u5C31\u907F\u514D\u4E86 Master \u8282\u70B9\u5F15\u53D1\u7684\u74F6\u9888\u95EE\u9898\u3002\u800C\u4E14\uFF0C\u7531\u4E8E\u5404\u4E2A JMeter \u662F\u5B8C\u5168\u72EC\u7ACB\u7684\uFF0C\u6240\u4EE5\u53EA\u8981 Jenkins Job \u8DB3\u591F\u591A\uFF0C\u5E76\u4E14\u7F51\u7EDC\u5E26\u5BBD\u4E0D\u4F1A\u6210\u4E3A\u74F6\u9888\u7684\u60C5\u51B5\u4E0B\uFF0C\u5C31\u80FD\u53D1\u8D77\u8DB3\u591F\u5927\u7684\u5E76\u53D1\u3002</p></li><li><p>\u6D4B\u8BD5\u811A\u672C\u3001\u6D4B\u8BD5\u6570\u636E\u548C\u6D4B\u8BD5\u7ED3\u679C\u5728\u5206\u5E03\u5F0F JMeter \u73AF\u5883\u4E2D\u7684\u5206\u53D1\u96BE\u9898\u3002\u5982\u679C\u76F4\u63A5\u91C7\u7528\u5206\u5E03\u5F0F\u7684 JMeter \u65B9\u6848\uFF0C\u6D4B\u8BD5\u811A\u672C\u9700\u8981\u901A\u8FC7 JMeter \u7684 Master \u8282\u70B9\u6765\u5206\u53D1\uFF0C\u6D4B\u8BD5\u6570\u636E\u6587\u4EF6\u5219\u8981\u7528\u6237\u81EA\u884C\u4E0A\u4F20\u81F3\u6BCF\u5957\u865A\u62DF\u673A\uFF0C\u540C\u65F6\u6D4B\u8BD5\u7ED3\u679C\u8FD8\u8981\u901A\u8FC7 JMeter \u7684 Slave \u8282\u70B9\u56DE\u4F20\u81F3 Master \u8282\u70B9\u3002\u6240\u4EE5\uFF0C\u66F4\u597D\u7684\u505A\u6CD5\u662F\u57FA\u4E8E JMeter \u6765\u642D\u5EFA\u4E00\u4E2A\u538B\u6D4B\u6846\u67B6\uFF0C\u8BF8\u5982\u811A\u672C\u5206\u53D1\u3001\u6570\u636E\u5206\u53D1\u4EE5\u53CA\u7ED3\u679C\u56DE\u4F20\u7B49\u5DE5\u4F5C\uFF0C\u90FD\u7531\u538B\u6D4B\u6846\u67B6\u5B8C\u6210\u3002\u8FD9\u4E5F\u662F\u76EE\u524D\u7EDD\u5927\u591A\u6570\u5927\u578B\u4E92\u8054\u7F51\u4F01\u4E1A\u7684\u505A\u6CD5\u3002\u6BD4\u5982\uFF0C\u997F\u4E86\u4E48\u5C31\u91C7\u7528\u8FD9\u79CD\u65B9\u5F0F\u642D\u5EFA\u4E86\u538B\u6D4B\u5E73\u53F0\uFF0C\u5E76\u4E14\u53D6\u5F97\u4E86\u5F88\u597D\u7684\u6548\u679C\u3002</p></li><li><p>\u6D41\u91CF\u53D1\u8D77\u7684\u5730\u57DF\u8981\u6C42\u3002\u5168\u94FE\u8DEF\u538B\u6D4B\u6D41\u91CF\u7684\u53D1\u8D77\u5F88\u591A\u65F6\u5019\u662F\u6709\u5730\u7406\u4F4D\u7F6E\u8981\u6C42\u7684\uFF0C\u6BD4\u5982 30%\u7684\u538B\u529B\u8D1F\u8F7D\u6765\u81EA\u4E0A\u6D77\u300130%\u7684\u538B\u529B\u8D1F\u8F7D\u6765\u81EA\u5317\u4EAC\u7B49\uFF0C\u8FD9\u5C31\u8981\u6C42\u6211\u4EEC\u5728\u591A\u4E2A\u57CE\u5E02\u7684\u6570\u636E\u4E2D\u5FC3\u90FD\u642D\u5EFA JMeter Slave\uFF0C\u4EE5\u4FBF\u53EF\u4EE5\u53D1\u8D77\u6765\u81EA\u591A\u4E2A\u5730\u57DF\u7684\u7EC4\u5408\u6D41\u91CF\u3002</p></li></ol><p><strong>\u5168\u94FE\u8DEF\u538B\u6D4B\u6D41\u91CF\u548C\u6570\u636E\u7684\u9694\u79BB</strong></p><p>\u56E0\u4E3A\u5168\u94FE\u8DEF\u538B\u6D4B\u662F\u5728\u5B9E\u9645\u7684\u751F\u4EA7\u73AF\u5883\u4E2D\u6267\u884C\u7684\uFF0C\u6240\u4EE5\u6D4B\u8BD5\u4EA7\u751F\u7684\u6570\u636E\u4E0E\u771F\u5B9E\u7684\u7528\u6237\u6570\u636E\u5FC5\u987B\u8FDB\u884C\u6709\u6548\u9694\u79BB\uFF0C\u4EE5\u9632\u6B62\u538B\u6D4B\u7684\u6D41\u91CF\u548C\u6570\u636E\u6C61\u67D3\u3001\u5E72\u6270\u751F\u4EA7\u73AF\u5883\u7684\u60C5\u51B5\u3002\u6BD4\u5982\uFF0C\u4E0D\u80FD\u5C06\u538B\u6D4B\u6570\u636E\u8BB0\u5F55\u5230\u7EDF\u8BA1\u5206\u6790\u62A5\u8868\u91CC\uFF1B\u518D\u6BD4\u5982\uFF0C\u538B\u6D4B\u5B8C\u6210\u540E\u53EF\u4EE5\u65B9\u4FBF\u5730\u6E05\u6D17\u6389\u538B\u6D4B\u4EA7\u751F\u7684\u6570\u636E\u3002</p><p>\u4E3A\u4E86\u8FBE\u5230\u8FD9\u4E2A\u76EE\u7684\uFF0C<strong>\u6211\u4EEC\u5C31\u9700\u8981\u5BF9\u538B\u6D4B\u6D41\u91CF\u8FDB\u884C\u7279\u6B8A\u7684\u6570\u636E\u6807\u8BB0\uFF0C\u4EE5\u533A\u522B\u4E8E\u771F\u5B9E\u7684\u6D41\u91CF\u548C\u6570\u636E</strong>\u3002\u8FD9\u5C31\u8981\u6C42\u5404\u4E2A\u94FE\u8DEF\u4E0A\u7684\u7CFB\u7EDF\uFF0C\u90FD\u80FD\u4F20\u9012\u548C\u5904\u7406\u8FD9\u79CD\u7279\u6B8A\u7684\u6570\u636E\u6807\u8BB0\uFF0C\u540C\u65F6\u5199\u5165\u6570\u636E\u5E93\u4E2D\u7684\u6570\u636E\u4E5F\u5FC5\u987B\u5E26\u6709\u8FD9\u79CD\u7C7B\u578B\u7684\u6807\u8BB0\u4EE5\u4FBF\u533A\u5206\u6570\u636E\uFF0C\u6216\u8005\u76F4\u63A5\u91C7\u7528\u4E13\u95E8\u7684\u5F71\u5B50\u6570\u636E\u5E93\u6765\u5B58\u50A8\u538B\u6D4B\u7684\u6570\u636E\u3002</p><p>\u53EF\u4EE5\u770B\u51FA\uFF0C\u4E3A\u4E86\u5B9E\u73B0\u538B\u6D4B\u4EA7\u751F\u7684\u548C\u771F\u5B9E\u7684\u6D41\u91CF\u548C\u6570\u636E\u9694\u79BB\uFF0C\u6211\u4EEC\u5C31\u9700\u8981\u5BF9\u5404\u4E2A\u4E1A\u52A1\u6A21\u5757\u548C\u4E2D\u95F4\u4EF6\u8FDB\u884C\u7279\u6B8A\u7684\u6539\u9020\u548C\u6269\u5C55\u3002\u800C\u8FD9\u4E2A\u5DE5\u4F5C\u91CF\u76F8\u5F53\u5927\uFF0C\u800C\u4E14\u7275\u6D89\u7684\u8303\u56F4\u4E5F\u975E\u5E38\u5E7F\uFF0C\u4E5F\u5C31\u8FDB\u4E00\u6B65\u589E\u52A0\u4E86\u5B9E\u65BD\u5168\u94FE\u8DEF\u538B\u6D4B\u7684\u96BE\u5EA6\u3002</p><p>\u800C\u4E14\u901A\u5E38\u6765\u8BB2\uFF0C\u9996\u6B21\u5168\u94FE\u8DEF\u538B\u6D4B\u7684\u51C6\u5907\u5468\u671F\u4F1A\u9700\u8981\u534A\u5E74\u4EE5\u4E0A\u7684\u65F6\u95F4\uFF0C\u8FD9\u5176\u4E2D\u6700\u5927\u7684\u5DE5\u4F5C\u91CF\u5728\u4E8E\u5BF9\u73B0\u6709\u4E1A\u52A1\u7CFB\u7EDF\u548C\u4E2D\u95F4\u4EF6\u7684\u6539\u9020\uFF0C\u6765\u5B9E\u73B0\u538B\u6D4B\u6D41\u91CF\u548C\u6570\u636E\u7684\u9694\u79BB\u3002\u6240\u4EE5\uFF0C\u5728\u5B9E\u9645\u7684\u5DE5\u7A0B\u9879\u76EE\u4E2D\uFF0C\u5982\u679C\u5168\u94FE\u8DEF\u538B\u6D4B\u4E0D\u662F\u7531\u9AD8\u5C42\u9886\u5BFC\u76F4\u63A5\u7275\u5934\u63A8\u52A8\u7684\u8BDD\uFF0C\u5F88\u96BE\u63A8\u8FDB\u3002</p><p>\u53E6\u5916\uFF0C\u5728\u5BF9\u5404\u4E2A\u4E1A\u52A1\u6A21\u5757\u548C\u4E2D\u95F4\u4EF6\u6DFB\u52A0\u7279\u6B8A\u6807\u8BB0\u7684\u6539\u9020\u8FC7\u7A0B\u4E2D\uFF0C\u6211\u4EEC\u4F1A\u5C3D\u53EF\u80FD\u5C11\u5730\u6539\u52A8\u4E1A\u52A1\u6A21\u5757\uFF0C\u800C\u662F\u66F4\u503E\u5411\u4E8E\u901A\u8FC7\u4E2D\u95F4\u4EF6\u6765\u5C3D\u53EF\u80FD\u591A\u5730\u5B8C\u6210\u7279\u6B8A\u6570\u636E\u6807\u8BB0\u7684\u5904\u7406\u548C\u4F20\u9012\u3002</p><p><strong>\u5B9E\u9645\u4E1A\u52A1\u8D1F\u8F7D\u7684\u6A21\u62DF</strong></p><p>\u4E00\u76F4\u4EE5\u6765\uFF0C\u5982\u4F55\u5C3D\u53EF\u80FD\u51C6\u786E\u5730\u6A21\u62DF\u4E1A\u52A1\u7CFB\u7EDF\u7684\u8D1F\u8F7D\uFF0C\u90FD\u662F\u8BBE\u8BA1\u5168\u94FE\u8DEF\u538B\u6D4B\u65F6\u7684\u96BE\u9898\u3002\u8FD9\u91CC\u7684\u96BE\u70B9\u4E3B\u8981\u4F53\u73B0\u5728\u4E24\u4E2A\u65B9\u9762\uFF1A\u9996\u5148\uFF0C\u8981\u4F30\u7B97\u8D1F\u8F7D\u7684\u603B\u4F53\u91CF\u7EA7\uFF1B\u5176\u6B21\uFF0C\u9700\u8981\u8BE6\u7EC6\u4E86\u89E3\u603B\u8D1F\u8F7D\u4E2D\u5404\u4E2A\u64CD\u4F5C\u7684\u5360\u6BD4\u60C5\u51B5\u4EE5\u53CA\u6267\u884C\u9891\u6B21\u3002</p><p>\u4E1A\u754C\u901A\u5E38\u91C7\u7528\u7684\u7B56\u7565\u662F\uFF0C\u91C7\u7528\u5DF2\u6709\u7684\u5386\u53F2\u8D1F\u8F7D\u4F5C\u4E3A\u57FA\u51C6\u6570\u636E\uFF0C\u7136\u540E\u5728\u6B64\u57FA\u7840\u4E0A\u8FDB\u884C\u9002\u5F53\u8C03\u6574\u3002\u5177\u4F53\u5230\u6267\u884C\u5C42\u9762\uFF0C\u901A\u5E38\u7684\u505A\u6CD5\u662F\uFF0C\u5F55\u5236\u5DF2\u6709\u7684\u5B9E\u9645\u7528\u6237\u8D1F\u8F7D\uFF0C\u7136\u540E\u5728\u6B64\u57FA\u7840\u4E0A\u505A\u4EE5\u4E0B\u4E24\u90E8\u5206\u4FEE\u6539\uFF1A</p><p>\u5F55\u5236\u6570\u636E\u7684\u6E05\u6D17\uFF0C\u5C06\u5F55\u5236\u5F97\u5230\u7684\u771F\u5B9E\u6570\u636E\u7EDF\u4E00\u66FF\u6362\u6210\u4E3A\u538B\u6D4B\u51C6\u5907\u7684\u6570\u636E\uFF0C\u6BD4\u5982\uFF0C\u9700\u8981\u5C06\u5F55\u5236\u5F97\u5230\u7684\u771F\u5B9E\u7528\u6237\u66FF\u6362\u6210\u4E13\u95E8\u4E3A\u538B\u6D4B\u51C6\u5907\u7684\u6D4B\u8BD5\u7528\u6237\u7B49\u7B49\xB7\uFF1B \u57FA\u4E8E\u7528\u6237\u6A21\u578B\u7684\u4F30\u7B97\uFF0C\u5728\u5168\u94FE\u8DEF\u538B\u6D4B\u8FC7\u7A0B\u4E2D\uFF0C\u6309\u6BD4\u4F8B\u653E\u5927\u5F55\u5236\u811A\u672C\u7684\u8D1F\u8F7D\u3002 \u6700\u540E\uFF0C\u518D\u7528\u8FD9\u4E2A\u8D1F\u8F7D\u6765\u6A21\u62DF\u5168\u94FE\u8DEF\u538B\u6D4B\u7684\u8D1F\u8F7D\u3002</p><p><strong>\u771F\u5B9E\u4EA4\u6613\u548C\u652F\u4ED8\u7684\u64A4\u9500\u4EE5\u53CA\u6570\u636E\u6E05\u7406</strong></p><p>\u7531\u4E8E\u5168\u94FE\u8DEF\u538B\u6D4B\u662F\u5728\u771F\u5B9E\u7684\u751F\u4EA7\u73AF\u5883\u4E2D\u8FDB\u884C\u7684\uFF0C\u90A3\u4E48\u5B8C\u6210\u7684\u6240\u6709\u4EA4\u6613\u4EE5\u53CA\u76F8\u5173\u7684\u652F\u4ED8\u90FD\u662F\u771F\u5B9E\u6709\u6548\u7684\uFF0C\u6240\u4EE5\u6211\u4EEC\u5C31\u9700\u8981\u5728\u6D4B\u8BD5\u7ED3\u675F\u540E\uFF0C\u5C06\u8FD9\u4E9B\u4EA4\u6613\u64A4\u9500\u3002</p><p>\u56E0\u4E3A\uFF0C\u6211\u4EEC\u5DF2\u7ECF\u5BF9\u8FD9\u4E9B\u4EA4\u6613\u7684\u6D41\u91CF\u548C\u6570\u636E\u8FDB\u884C\u4E86\u7279\u5B9A\u6807\u8BB0\uFF0C\u6240\u4EE5\u6211\u4EEC\u53EF\u4EE5\u6BD4\u8F83\u65B9\u4FBF\u5730\u7B5B\u9009\u51FA\u9700\u8981\u64A4\u9500\u7684\u4EA4\u6613\uFF0C\u7136\u540E\u901A\u8FC7\u81EA\u52A8\u5316\u811A\u672C\u7684\u65B9\u5F0F\u6765\u5B8C\u6210\u6279\u91CF\u7684\u6570\u636E\u6E05\u7406\u5DE5\u4F5C\u3002</p><p>\u9664\u4E86\u4E0A\u9762\u7684\u56DB\u5927\u95EE\u9898\u4EE5\u5916\uFF0C\u5168\u94FE\u8DEF\u538B\u6D4B\u8FD8\u9700\u8981\u8003\u8651\u6D4B\u8BD5\u6267\u884C\u8FC7\u7A0B\u4E2D\u7684\u6027\u80FD\u76D1\u63A7\u3001\u9AD8\u5F3A\u5EA6\u538B\u6D4B\u8D1F\u8F7D\u4E0B\u7684\u6D4B\u8BD5\u7194\u65AD\u673A\u5236\u3001\u5168\u94FE\u8DEF\u538B\u6D4B\u6267\u884C\u671F\u95F4\u5BF9\u539F\u6709\u7CFB\u7EDF\u6B63\u5E38\u8D1F\u8F7D\u7684\u5F71\u54CD\u3001\u5168\u94FE\u8DEF\u538B\u6D4B\u6570\u636E\u5BF9\u5916\u7684\u4E0D\u53EF\u89C1\u7B49\u7B49\u3002</p><p>\u6240\u4EE5\u8BF4\uFF0C\u5168\u94FE\u8DEF\u538B\u6D4B\u7684\u6280\u672F\u542B\u91CF\u5F88\u9AD8\uFF0C\u800C\u4E14\u9700\u8981\u591A\u65B9\u5171\u540C\u914D\u5408\u624D\u6709\u53EF\u80FD\u987A\u5229\u5B8C\u6210\u3002\u6240\u4EE5\uFF0C\u4ECA\u5929\u8FD9\u7BC7\u6587\u7AE0\u7684\u76EE\u7684\uFF0C\u610F\u5728\u629B\u7816\u5F15\u7389\u3002\u5E0C\u671B\u4F60\u53EF\u4EE5\u501F\u7531\u8FD9\u7BC7\u6587\u7AE0\uFF0C\u5148\u5BF9\u5168\u94FE\u8DEF\u538B\u6D4B\u7684\u96BE\u70B9\u4EE5\u53CA\u5BF9\u5E94\u7684\u89E3\u51B3\u601D\u8DEF\u6709\u4E2A\u5168\u5C40\u7684\u8BA4\u8BC6\u3002\u800C\u5982\u679C\u4F60\u60F3\u8981\u66F4\u597D\u5730\u4E86\u89E3\u5E76\u638C\u63E1\u5168\u94FE\u8DEF\u538B\u6D4B\uFF0C\u6700\u597D\u7684\u65B9\u5F0F\u8FD8\u662F\u8981\u5728\u5B9E\u9645\u9879\u76EE\u4E2D\u591A\u52A0\u5386\u7EC3\u3002</p><p>\u53E6\u5916\uFF0C\u4F60\u8FD8\u53EF\u4EE5\u53C2\u8003\u4E00\u4E9B\u7F51\u4E0A\u7684\u4F18\u79C0\u8D44\u6E90\uFF0C\u6211\u5728\u8FD9\u91CC\u5217\u51FA\u4E86\u4E24\u6761\u4F9B\u4F60\u53C2\u8003\uFF1A</p><p>https://mp.weixin.qq.com/s?__biz=MzIzMzk2NDQyMw==&amp;mid=2247486703&amp;idx=1&amp;sn=0c448c40469e6a8f32476a7c7fbab6cd&amp;source=41#wechat_redirect</p><p>https://www.cnblogs.com/imyalost/p/8439910.html</p><p><strong>\u603B\u7ED3</strong></p><p>\u4ECA\u5929\u8FD9\u7BC7\u6587\u7AE0\uFF0C\u6211\u548C\u4F60\u5206\u4EAB\u4E86\u5168\u94FE\u8DEF\u538B\u6D4B\u7684\u57FA\u672C\u77E5\u8BC6\uFF0C\u4EE5\u53CA\u5728\u5F00\u5C55\u5168\u94FE\u8DEF\u538B\u6D4B\u7684\u96BE\u70B9\u3001\u5BF9\u5E94\u7684\u89E3\u51B3\u601D\u8DEF\u3002\u73B0\u5728\uFF0C\u6211\u518D\u548C\u4F60\u4E00\u8D77\u56DE\u987E\u4E0B\u3002</p><p>\u5168\u94FE\u8DEF\u538B\u6D4B\uFF0C\u662F\u57FA\u4E8E\u771F\u5B9E\u7684\u751F\u4EA7\u73AF\u5883\u6765\u6A21\u62DF\u6D77\u91CF\u5E76\u53D1\u7528\u6237\u8BF7\u6C42\u548C\u6570\u636E\uFF0C\u5BF9\u6574\u4E2A\u4E1A\u52A1\u94FE\u8DEF\u8FDB\u884C\u538B\u529B\u6D4B\u8BD5\uFF0C\u8BD5\u56FE\u627E\u5230\u6240\u6709\u6F5C\u5728\u6027\u80FD\u74F6\u9888\u70B9\u5E76\u6301\u7EED\u4F18\u5316\u7684\u5B9E\u8DF5\u3002\u5B83\u7684\u5E94\u7528\u9886\u57DF\u4E0D\u4EC5\u4EC5\u5305\u542B\u9A8C\u8BC1\u7CFB\u7EDF\u5728\u5CF0\u503C\u671F\u95F4\u7684\u7A33\u5B9A\u6027\uFF0C\u8FD8\u4F1A\u5305\u542B\u65B0\u7CFB\u7EDF\u4E0A\u7EBF\u540E\u7684\u6027\u80FD\u74F6\u9888\u5B9A\u4F4D\u4EE5\u53CA\u7AD9\u70B9\u5BB9\u91CF\u7684\u7CBE\u51C6\u89C4\u5212\u3002</p><p>\u4E86\u89E3\u4E86\u5168\u94FE\u8DEF\u7684\u57FA\u672C\u6982\u5FF5\uFF0C\u4EE5\u53CA\u9002\u7528\u573A\u666F\u540E\uFF0C\u6211\u548C\u4F60\u5206\u4EAB\u4E86\u5168\u94FE\u8DEF\u538B\u6D4B\u4E2D\u6700\u5173\u952E\u7684\u56DB\u4E2A\u6280\u672F\u96BE\u70B9\uFF0C\u5373\uFF1A\u6D77\u91CF\u5E76\u53D1\u8BF7\u6C42\u7684\u53D1\u8D77\u3001\u5168\u94FE\u8DEF\u538B\u6D4B\u6D41\u91CF\u548C\u6570\u636E\u7684\u9694\u79BB\u3001\u5B9E\u9645\u4E1A\u52A1\u8D1F\u8F7D\u7684\u6A21\u62DF\uFF0C\u4EE5\u53CA\u6D4B\u8BD5\u5B8C\u6210\u540E\u7684\u6570\u636E\u6E05\u7406\u3002</p><p>\u6D77\u91CF\u5E76\u53D1\u8BF7\u6C42\u7684\u53D1\u8D77\u4E3B\u8981\u501F\u52A9\u4E8E JMeter\uFF0C\u5E76\u4E14\u901A\u8FC7 Jenkins Job \u6765\u5B9E\u73B0\u6D77\u91CF\u5E76\u53D1\u7684\u8C03\u5EA6\u63A7\u5236\uFF1B \u5168\u94FE\u8DEF\u538B\u6D4B\u6D41\u91CF\u548C\u6570\u636E\u7684\u9694\u79BB\u4E3B\u8981\u501F\u52A9\u542B\u6709\u7279\u5B9A\u6807\u8BB0\u7684\u6D41\u91CF\u548C\u6570\u636E\u6765\u5B9E\u73B0\uFF0C\u540C\u65F6\u9700\u8981\u5BF9\u4E1A\u52A1\u6A21\u5757\u4EE5\u53CA\u4E2D\u95F4\u4EF6\u8FDB\u884C\u5FC5\u8981\u7684\u6539\u9020\uFF0C\u6570\u636E\u5E93\u8FD9\u8FB9\u8FD8\u4F1A\u4F7F\u7528\u5F71\u5B50\u6570\u636E\u5E93\uFF1B \u5B9E\u9645\u4E1A\u52A1\u8D1F\u8F7D\u7684\u6A21\u62DF\uFF0C\u4E3B\u8981\u662F\u91C7\u7528\u57FA\u4E8E\u5386\u53F2\u6D41\u91CF\u4FEE\u6539\u540E\u7684\u56DE\u653E\u6765\u5B9E\u73B0\uFF1B \u5168\u94FE\u8DEF\u538B\u6D4B\u5B8C\u6210\u540E\u7684\u6570\u636E\u6E05\u6D17\uFF0C\u5219\u662F\u501F\u52A9\u81EA\u52A8\u5316\u7684\u624B\u6BB5\u6765\u6279\u91CF\u5B8C\u6210\u3002</p><p><strong>\u601D\u8003\u9898</strong></p><p>\u4F60\u80FD\u60F3\u5230\u5168\u94FE\u8DEF\u538B\u6D4B\u4E2D\u8FD8\u6709\u54EA\u4E9B\u6280\u672F\u4E0A\u7684\u96BE\u70B9\u5417\uFF1F</p>',54);function n(i,l){return t}var s=p(r,[["render",n],["__file","53.html.vue"]]);export{s as default};
